export function applyMappedResponseObject(
	source: Record<string, any>,
	target: Record<string, any>,
	map: Record<string, string>,
) {
	if (!source || typeof source !== 'object') return source;
	const copy = structuredClone(source);

	for (const k of Object.keys(target)) {
		const mappedPath = map[k];
		if (mappedPath !== undefined) {
			apply(copy, mappedPath, target[k]);
		}
	}

	return copy;
}

const ALLOWED_BOOLEAN_VALUES = ['true', 'false', '1', '0', 1, 0];

function apply(source: Record<string, any>, path: string, value: any) {
	const parts = path.split('.');
	let pointer: any = source;

	for (const p of parts.slice(0, -1)) {
		if (!pointer || typeof pointer !== 'object') return;
		pointer = pointer[p];
	}

	const lastKey = parts.at(-1);
	if (lastKey !== undefined) {
		const originalValue = pointer[lastKey];
		const originalType = typeof originalValue;

		switch (originalType) {
			case 'object':
				if (originalValue === null) {
					pointer[lastKey] = value;
				} else if (Array.isArray(originalValue)) {
					try {
						pointer[lastKey] = JSON.parse(value);
					} catch {
						console.error(
							`Failed to parse mock response override for an original value of Array type. The override must be a valid JSON string. Attempted to parse ${value}.`,
						);
					}
				} else {
					console.error(`Mock response override cannot be an object.`);
				}
				break;
			case 'number': {
				const parsed = Number(value);
				if (!Number.isNaN(parsed)) {
					pointer[lastKey] = parsed;
				} else {
					console.error(
						`Mock response override for an original value of number type cannot be parsed. Attempted to parse ${value}.`,
					);
				}
				break;
			}
			case 'boolean':
				if (ALLOWED_BOOLEAN_VALUES.includes(value)) {
					pointer[lastKey] = value === 'true' || value === 1 || value === '1';
				} else {
					console.error(
						`Mock response override for an original value of boolean type cannot be parsed. Allowed values are ${ALLOWED_BOOLEAN_VALUES.join(
							', ',
						)}. Attempted to parse ${value}.`,
					);
				}
				break;
			case 'string':
				pointer[lastKey] = value;
				break;
			default:
				console.error(
					`Mock response override for an original value of type ${originalType} is not supported. Only string, number, boolean and array types are supported. Attempted to override a value of type ${originalType} with value ${value}.`,
				);
		}
	}
}
