import { CookieBooleanSignal, LAB_MODE_COOKIE } from 'utils/cookieStorage';
import { isProduction } from 'utils/env';
import { toastMessages } from 'components/toastMessage/signals';
import { getUserSelf } from 'service/user/resource';

const EXPIRES_IN_30_DAYS = 30 * 24 * 60 * 60 * 1000;

export const labModeActiveSignal = new CookieBooleanSignal(!isProduction(), LAB_MODE_COOKIE, EXPIRES_IN_30_DAYS);

export function initLabModeFromSSR(ssrValue: boolean) {
	labModeActiveSignal.value = ssrValue;
}

export function toggleLabModeWithReload(): void {
	const newValue = !labModeActiveSignal.peek();

	labModeActiveSignal.value = newValue;

	toastMessages.info(newValue ? '🧪 Lab Mode byl aktivován!' : '🧪 Lab Mode byl deaktivován', { timeoutMs: 2000 });

	globalThis.location?.reload();
}

export async function isEmployee(userRequestHeaders?: Headers) {
	const userData = await getUserSelf({}, userRequestHeaders);
	const { login } = userData;
	return login ? login.endsWith('@firma.seznam.cz') : false;
}

export async function isAllowedToSeeLabMode() {
	if (!isProduction()) return true;

	return await isEmployee();
}

export function isLabMode() {
	return labModeActiveSignal.peek();
}
